package be.schaubroeck.lpb.rkm.rekenmotor.planningsuren;

import be.schaubroeck.lpb.rkm.rekenmotor.RekenContext;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.UitzPerUurModus;
import be.schaubroeck.lpb.rkm.rekenmotor.util.CodeExtensie;
import be.schaubroeck.lpb.rkm.rekenmotor.util.ConstantManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonCodeManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonCodeTools;
import be.schaubroeck.lpb.rkm.rekenmotor.util.PersoonsDataManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.PrestatieSamenvattingUitzPerUur;
import be.schaubroeck.lpb.tools.AardKodeExtensie;
import be.schaubroeck.lpb.tools.NlpPrestatie;
import be.schaubroeck.lpb.tools.Opdracht;
import be.schaubroeck.lpb.tools.Opper;
import be.schaubroeck.lpb.tools.caching.ake.AardKodeExtensieFacade;
import be.schaubroeck.lpb.tools.enumtypes.AardKodeExt;
import be.schaubroeck.lpb.tools.enumtypes.Konstanten;
import be.schaubroeck.lpb.tools.enumtypes.Maandverwerking;
import be.schaubroeck.lpb.tools.enumtypes.TypeUitzonderlijkPerUur;
import com.google.common.collect.ImmutableSet;

import java.math.BigDecimal;
import java.util.List;
import java.util.Set;

public class UitzonderlijkPerUurOld implements UitzonderlijkPerUur {

    private static final Set<Integer> CODES_UITZONDERLIJK_PER_UUR = ImmutableSet.of(311, 280);
    private static final Set<Integer> CODES_UITZONDERLIJK_PER_UUR_VANAF_07_2024 = ImmutableSet.of(311, 280, 281);
    private static final Set<Integer> CODES_UITZONDERLIJK_PER_UUR_CLUSTER_TURNHOUT = ImmutableSet.of(323);
    private static final Set<CodeExtensie> CODE_EXTENSIES_UITZONDERLIJK_PER_UUR_CLUSTER_TURNHOUT = ImmutableSet.of(
            CodeExtensie.ONBETAALD_VERLOF_GUNST_105,
            CodeExtensie.ONBETAALD_VERLOF_GUNST_205,
            CodeExtensie.ONBETAALD_VERLOF_RECHT_105);
    private static final Set<Integer> TE_EXCLUDEREN_VOOR_NOEMER_UTIZ_PER_UUR = ImmutableSet.of(220, 303, 307, 308, 309, 317, 324, 326, 361, 155);
    private static final Set<CodeExtensie> TE_EXCLUDEREN_VOOR_NOEMER_UTIZ_PER_UUR_B = ImmutableSet.of(
            CodeExtensie.MANTELZORG,
            CodeExtensie.VRIJWILLIGE_4_DAGEN_WEEK,
            CodeExtensie.HALFTIJDS_VERVROEGDE_UITTREDING,
            CodeExtensie.VERLOF_DEELTIJDSE_PRESTATIES,
            CodeExtensie.POLITIE_VERLOF_NIET_GELIJKGESTELD_DIENSTACTIVITEIT);
    private static final Set<CodeExtensie> WEL_INCLUDEREN_VOOR_NOEMER_UTIZ_PER_UUR = ImmutableSet.of(
            CodeExtensie.ONBETAALD_VERLOF_GUNST_105,
            CodeExtensie.ONBETAALD_VERLOF_GUNST_205,
            CodeExtensie.ONBETAALD_VERLOF_RECHT_105);
    private static final Integer CODE_VRIJWILLIGE_4_DAGEN_WEEK = 290;
    private static final Set<Integer> EXTENSIES_VRIJWILLIGE_4_DAGEN_WEEK_AFWEZIGHEID = ImmutableSet.of(2, 3, 4, 61);

    private final ConstantManager constantManager;
    private final AardKodeExtensieFacade aardKodeExtensieFacade;

    public UitzonderlijkPerUurOld(ConstantManager constantManager, AardKodeExtensieFacade aardKodeExtensieFacade) {
        this.constantManager = constantManager;
        this.aardKodeExtensieFacade = aardKodeExtensieFacade;
    }

    private boolean isCodeUizonderlijkPerUur(NlpPrestatie prestatie, TypeUitzonderlijkPerUur typeUitzPerUur) {
        boolean dagOfKalenderCode = prestatie.getAard().equals(AardKodeExt.D_KODE_EXT.getCode()) || prestatie.getAard().equals(AardKodeExt.K_KODE_EXT.getCode());
        if (typeUitzPerUur == TypeUitzonderlijkPerUur.CLUSTER_ANTWERPEN) {
            return CODES_UITZONDERLIJK_PER_UUR.contains(prestatie.getCode()) && dagOfKalenderCode;
        } else if (typeUitzPerUur == TypeUitzonderlijkPerUur.CLUSTER_TURNHOUT) {
            boolean codeUitzPerUurTurnhout = LoonCodeTools.matches(prestatie.getCode(), prestatie.getExtensie(), CODE_EXTENSIES_UITZONDERLIJK_PER_UUR_CLUSTER_TURNHOUT);
            codeUitzPerUurTurnhout = codeUitzPerUurTurnhout || CODES_UITZONDERLIJK_PER_UUR_CLUSTER_TURNHOUT.contains(prestatie.getCode());
            return codeUitzPerUurTurnhout && dagOfKalenderCode;
        } else if (typeUitzPerUur == TypeUitzonderlijkPerUur.CLUSTER_ANTWERPEN_2024) {
            return CODES_UITZONDERLIJK_PER_UUR_VANAF_07_2024.contains(prestatie.getCode()) && dagOfKalenderCode;
        } else {
            return false;
        }
    }

    public UitzPerUurModus bepaal(PersoonsDataManager dataManager, Opdracht opdracht, RekenTijd rekenTijd) {
        int typeUitzPerUurCode = constantManager.getByCodeDatum(Konstanten.KST_UITZONDERLIJKE_UURREKENING_1, rekenTijd.beginDatum).getInteger();
        TypeUitzonderlijkPerUur typeUitzPerUur = TypeUitzonderlijkPerUur.getByCode(typeUitzPerUurCode);
        boolean heeftDertigsten = opdracht.getOpperSlices().stream()
                .anyMatch(x -> x.getWeddeBerekening().getOmzettingLoonMaandNaarDag() == Maandverwerking.DERTIGSTEN);
        boolean isUitzonderlijkPerUur = opdracht.getOpperSlices().stream()
                .anyMatch(x -> x.getWeddeBerekening().getOmzettingLoonMaandNaarDag() == Maandverwerking.PLANNINGSUREN);
        List<NlpPrestatie> prestaties = dataManager.findPrestaties(opdracht, rekenTijd.eindDatum);
        if (!isUitzonderlijkPerUur) {
            isUitzonderlijkPerUur = typeUitzPerUur != TypeUitzonderlijkPerUur.NVT && heeftDertigsten
                    && prestaties.stream().anyMatch(x -> isCodeUizonderlijkPerUur(x, typeUitzPerUur));
        }
        UitzPerUurModus uitzPerUurModus = UitzPerUurModus.GEEN;
        if (isUitzonderlijkPerUur) {
            boolean isUitzPerUurMetLangdurigAfwezigheid = prestaties.stream().anyMatch(x -> excluderenInNoemer(x.getCode(), x.getExtensie()));
            if (isUitzPerUurMetLangdurigAfwezigheid) {
                uitzPerUurModus = UitzPerUurModus.UITZ_PER_UUR_LANGDURIG_AFWEZIGHEID;
            } else {
                uitzPerUurModus = UitzPerUurModus.UIITZONDERLIJK_PER_UUR;
            }
        }
        return uitzPerUurModus;
    }


    public boolean excluderenInNoemer(Integer code, Integer extensie) {
        boolean excludedOnCode = TE_EXCLUDEREN_VOOR_NOEMER_UTIZ_PER_UUR.contains(code);
        boolean excludedOnCodeExtensie = LoonCodeTools.matches(code, extensie, TE_EXCLUDEREN_VOOR_NOEMER_UTIZ_PER_UUR_B);
        boolean includeExceptions = LoonCodeTools.matches(code, extensie, WEL_INCLUDEREN_VOOR_NOEMER_UTIZ_PER_UUR);
        return (excludedOnCode || excludedOnCodeExtensie) && !includeExceptions;
    }

    public boolean includerenDagCode(AardKodeExtensie looncode) {
        return !(aardKodeExtensieFacade.isAfwezigheidsCode(looncode) && !(looncode.getCode() >= 100 && looncode.getCode() <= 199) &&
                !(ziekteVrijwillige4DagenWeek(looncode)));
    }

    private boolean ziekteVrijwillige4DagenWeek(AardKodeExtensie looncode) {
        return looncode.getCode().equals(CODE_VRIJWILLIGE_4_DAGEN_WEEK) && EXTENSIES_VRIJWILLIGE_4_DAGEN_WEEK_AFWEZIGHEID.contains(looncode.getExtensie());
    }

    public boolean includerenKalenderCode(AardKodeExtensie looncode) {
        return looncode.getCode() >= 100 && looncode.getCode() <= 199 && looncode.getCode() != 155;
    }

    public boolean isLangdurigeAfwezigheid(Opdracht opdracht, Integer code, Integer extensie) {
        return false;
    }

    @Override
    public void bepaalTotaalAantalUren(RekenContext opdrachtContext, Opdracht opdracht) {
        UitzPerUurModus uitzPerUurModus = opdrachtContext.getUnchecked(RekenChainKey.UITZONDERLIJK_PER_UUR_KEY);
        if (uitzPerUurModus != UitzPerUurModus.GEEN) {
            BigDecimal totaalAantalUren = BigDecimal.ZERO;
            for (Opper opper : opdracht.getOpperSlices()) {
                PrestatieSamenvattingUitzPerUur samenvatting = opdrachtContext.getDoubleKey(RekenChainKey.PRESTATIE_SAMENVATTING_UIT_PER_UUR_KEY, opper);
                totaalAantalUren = totaalAantalUren.add(samenvatting.getTotaalAantalUren());
            }

            for (Opper opper : opdracht.getOpperSlices()) {
                PrestatieSamenvattingUitzPerUur samenvatting = opdrachtContext.getDoubleKey(RekenChainKey.PRESTATIE_SAMENVATTING_UIT_PER_UUR_KEY, opper);
                samenvatting.setTotaalAantalUren(totaalAantalUren);
            }
        }
    }

    @Override
    public boolean onderzoekBezoldigdePrestatiesAanwezig(
            Opdracht opdracht, List<NlpPrestatie> prestaties, LoonCodeManager loonCodeManager, UitzPerUurModus uitzPerUurModus) {
        return UitzonderlijkPerUurBezoldigdePrestatiesOnderzoek.onderzoek(opdracht, prestaties, loonCodeManager, uitzPerUurModus, this);
    }
}
